const hooks = [
  'Tiny systems beat huge plans.',
  'Ship daily, improve weekly.',
  'Automate the boring parts first.',
  'Consistency compounds faster than motivation.'
];

const hashtags = ['#buildinpublic', '#AI', '#automation', '#n8n'];
const pick = (arr) => arr[Math.floor(Math.random() * arr.length)];

const tweet = `${pick(hooks)} ${pick(hashtags)} ${pick(hashtags)}`;

return [{
  tweet,
  createdAt: new Date().toISOString()
}];

const bannedWords = ['scam', 'nsfw', 'slur'];
const maxLength = 270;

let tweet = String($json.tweet || '').replace(/\s+/g, ' ').trim();

if (tweet.length > maxLength) {
  tweet = `${tweet.slice(0, maxLength - 1).trimEnd()}…`;
}

const lowered = tweet.toLowerCase();
const bannedWord = bannedWords.find((word) => lowered.includes(word));

let duplicateDetected = false;

try {
  const globalData = $getWorkflowStaticData('global');
  if (globalData.lastTweet === tweet) {
    duplicateDetected = true;
    tweet = `${tweet} #DailyBuild`;
    if (tweet.length > 280) {
      tweet = `${tweet.slice(0, 279)}…`;
    }
  }

  if (!bannedWord && tweet) {
    globalData.lastTweet = tweet;
  }
} catch (error) {
  // If static data isn't available, continue without duplicate memory.
}

const shouldPost = Boolean(tweet) && !bannedWord;

return [{
  tweet,
  length: tweet.length,
  createdAt: new Date().toISOString(),
  shouldPost,
  duplicateDetected,
  skipReason: shouldPost ? '' : `Blocked by guardrails (${bannedWord ? `contains ${bannedWord}` : 'empty tweet'})`
}];

return [{
  posted: false,
  reason: $json.skipReason || 'Unknown guardrail failure',
  createdAt: new Date().toISOString()
}];
